function reverseVowels(s) {
    const vowels = new Set('aeiouAEIOU');
    let chars = Array.from(s);
    let i = 0, j = s.length - 1;
    while (i < j) {
        if (!vowels.has(chars[i])) {
            i++;
        } else if (!vowels.has(chars[j])) {
            j--;
        } else {
            [chars[i], chars[j]] = [chars[j], chars[i]];
            i++;
            j--;
        }
    }
    return chars.join('');
}
